  ('4c13293e-eac3-456b-a411-3f4b5a19ad7d', $$Scheikunde$$, $$VWO$$, $$Waterstofauto’s die methaanzuur tanken$$, $$VWO Scheikunde 2021-II$$),
  ('b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$Scheikunde$$, $$VWO$$, $$Retinal in het oog$$, $$VWO Scheikunde 2021-II$$),
  ('30d00c2e-bdf8-4d98-9e5a-48941e555fb0', $$Scheikunde$$, $$VWO$$, $$Slim gebruik van glycerol$$, $$VWO Scheikunde 2021-II$$),
  ('d7245c72-3848-4cbb-a38a-6f8a59157865', $$Scheikunde$$, $$VWO$$, $$Doerian, een delicatesse?$$, $$VWO Scheikunde 2021-II$$);

insert into practice_context_blocks (id, exercise_id, label, image_url, text_content, block_type) values
  ('a9f7fbaa-9912-478b-ac9c-63a26e668f9f', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', $$inleiding — bereiding methaanzuur uit waterstof (stap 1-3)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-context1.png$$,
   $$Omdat de opslag van waterstof een probleem is, wordt onderzoek gedaan naar manieren om waterstof om te zetten tot stoffen met een hogere dichtheid. Een voorbeeld van zo’n stof is methaanzuur (HCOOH). Methaanzuur wordt momenteel industrieel bereid in drie stappen:
1 Waterstof reageert met koolstofdioxide tot methanol en water.
2 Methanol reageert met koolstofmono-oxide tot methylmethanoaat.
3 Methylmethanoaat reageert met water tot methaanzuur en methanol.$$, 'inline'),
  ('bec82752-c2ce-4ae4-b1e7-6e9a540b56b8', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', $$molverhouding methaanzuur : methanol = 1 : 1$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-context2.png$$,
   $$In totaal komt het proces neer op de omzetting van waterstof met CO₂ en CO tot methaanzuur en methanol. Methaanzuur en methanol ontstaan hierbij in de molverhouding 1 : 1.$$, 'inline'),
  ('2dedf94c-cd97-4cec-a860-36a7bfe54270', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', $$omzetting HCOOH → H2+CO2 in een auto; Hyundai-gegevens$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-context3.png$$,
   $$Als het technisch mogelijk is om methaanzuur in een auto om te zetten tot waterstof en koolstofdioxide, kan de auto de vrijgekomen waterstof gebruiken als brandstof. De omzetting van methaanzuur tot waterstof in een auto is hieronder weergegeven.
HCOOH → H₂ + CO₂
Een Hyundai-waterstofauto kan 594 km rijden op 5,64 kg waterstof.
De dichtheid van methaanzuur is 1,22 kg L⁻¹.$$, 'inline'),
  ('d8826dda-e56f-49f7-af2d-ad60284b6b53', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', $$katalysator voor directe omzetting H2+CO2 in basisch milieu$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-context4.png$$,
   $$Twee onderzoeksgroepen hebben een katalysator ontwikkeld die de directe omzetting van H₂ en CO₂ tot methaanzuur katalyseert. Omdat deze omzetting in basisch milieu optreedt, wordt er geen methaanzuur gevormd, maar onder andere het zuurrest-ion van methaanzuur.$$, 'inline'),
  ('90538c82-a1ff-4b31-8ffc-0709e50c7060', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', $$figuur — evenwicht [H4kat]4+ ⇌ [kat]0 met Ir-katalysatorcomplex$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-context5.png$$,
   $$Afhankelijk van de pH komen in oplossingen van de gebruikte katalysator voornamelijk deeltjes [H₄kat]⁴⁺ of deeltjes [kat]⁰ voor. In de figuur is het evenwicht tussen deze deeltjes weergegeven met structuurformules.
figuur: de structuurformules van de twee katalysatordeeltjes, elk met twee iridium-ionen die via stikstofatomen van pyrimidine-achtige ringen en zuurstofatomen aan elkaar en aan X⁻-groepen en watermoleculen zijn gebonden (stippellijnen geven elektrostatische interacties aan); in [H₄kat]⁴⁺ zijn de zuurstofatomen van de ringen als OH-groepen aanwezig (lading 4+ op het geheel), in [kat]⁰ zijn dezelfde zuurstofatomen gedeprotoneerd tot O⁻-groepen, onder afsplitsing van 4 H⁺.$$, 'inline'),
  ('b2c31a2c-2a88-4cad-a76b-45b6b89fb26d', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', $$toelichting figuur — ladingen en interacties van de Ir-ionen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-context6.png$$,
   $$In elk katalysatordeeltje zijn twee iridium-ionen door elektrostatische interacties gebonden aan enkele omringende deeltjes. Deze interacties zijn in de figuur weergegeven met stippellijnen. In de figuur zijn alle formele ladingen aangegeven, behalve de lading van de iridium-ionen. Alle iridium-ionen in de figuur hebben dezelfde lading.$$, 'inline'),
  ('e5520238-b7fa-4db0-a1d6-1eda185e4c09', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', $$intro vraag 6 — Lewisstructuur van deeltje X⁻ op de uitwerkbijlage$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-context7.png$$,
   $$Op de uitwerkbijlage is een Lewisstructuur van het deeltje X⁻ weergegeven. Een andere grensstructuur is onvolledig weergegeven.$$, 'inline'),
  ('0af3fc45-c08e-4f4e-bb0c-3fd436f837c9', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', $$katalysator ook werkzaam voor omzetting in een auto bij lage pH$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-context8.png$$,
   $$De gebruikte katalysator is ook werkzaam bij de omzetting van methaanzuur tot H₂ en CO₂ in een auto. Deze omzetting treedt alleen op bij lage pH.$$, 'inline'),
  ('0ab93e0f-fef0-4544-9fd5-0bbca6ed009b', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', $$uitwerkbijlage vraag 6 — grensstructuren van deeltje X⁻$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-context9.png$$,
   $$Linker grensstructuur (gegeven): een vijfring van vijf C-atomen, elk met een CH₃-zijgroep, met een negatieve lading op het bovenste C-atoom en twee C=C-dubbele bindingen naar de onderste twee C-atomen. Rechter grensstructuur (onvolledig, aan te vullen): dezelfde vijfring zonder de dubbele binding(en) en lading al ingetekend — de formele lading(en) en de C=C-binding(en) moeten zo worden toegevoegd dat alle C-atomen aan de oktetregel voldoen.$$, 'uitwerkbijlage'),
  ('48a4ed30-8793-431f-a1ca-b338f59eccd1', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$inleiding — opsine, retinal en cis/trans-isomerisatie$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context1.png$$,
   $$In de cellen van het netvlies bevindt zich het eiwit opsine. In een holte van het opsine-molecuul is een molecuul retinal covalent gebonden aan de restgroep van de aminozuureenheid lysine. Bij absorptie van lichtenergie treedt in retinal op één plaats in het molecuul cis/trans-isomerisatie op. Als gevolg van deze verandering ontstaat uiteindelijk een signaal in de oogzenuw. In figuur 1 is de structuurformule van retinal weergegeven. Hierbij is informatie over stereo-isomerie in retinal weggelaten.$$, 'inline'),
  ('d739e561-d96e-433b-a72d-c4a252e12650', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$figuur 1 — structuurformule van retinal (C-nummering)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context2.png$$,
   $$figuur 1: volledige structuurformule van retinal met genummerde koolstofatomen (C1 t/m C20); een cyclohexeenring (C1-C6, met een gem-dimethylgroep op C1 en een CH₃-groep op C5) is via C7=C8 verbonden met een geconjugeerde polyeenketen (C9=C10-C11=C12-C13=C14-C15) met CH₃-zijgroepen op C9 en C13, eindigend in een aldehydegroep (C15=O, C15-H).$$, 'inline'),
  ('e2d10d9f-ab8d-46f6-b2bd-3e92102326d5', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$cis/trans-isomerisatie treedt bij opsine op tussen C11 en C12$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context3.png$$,
   $$In een retinal-molecuul is cis/trans-isomerisatie op een aantal plaatsen mogelijk. De biochemicus George Wald (Nobelprijs 1967) heeft ontdekt dat uitsluitend de dubbele binding tussen C11 en C12 onder invloed van licht isomeriseert van het in opsine aanwezige cis naar trans; dit is de eerste stap van de waarneming van licht.$$, 'inline'),
  ('ab730798-14c8-461d-bc39-ae669c30ec66', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$retinal-analogon stof A (cis/trans-isomerisatie C11=C12 geblokkeerd)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context4.png$$,
   $$In het onderzoek van Wald is gebruikgemaakt van retinal-analoga. Dit zijn stoffen waarbij in het retinal-molecuul op verschillende plaatsen de cis/trans-isomerisatie is geblokkeerd. Hiernaast is de structuurformule van zo’n stof (stof A) weergegeven. In het molecuul van stof A is cis-/trans-isomerisatie van de dubbele binding tussen C11 en C12 onmogelijk. Dit molecuul kan worden opgevat als een molecuul retinal waarin onder andere een extra koolstofatoom in de structuur is opgenomen.
stof A: dezelfde cyclohexeenring en polyeenketen als retinal, maar met een extra koolstofatoom dat een tweede ring sluit rond de C11=C12-omgeving, waardoor deze dubbele binding niet meer kan isomeriseren; de keten eindigt net als bij retinal in een aldehydegroep.$$, 'inline'),
  ('d88f31da-0d24-487e-8789-1b19c269d6e5', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$inleiding figuur 2 — loskoppelen van retinal van opsine (stap 1)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context5.png$$,
   $$In figuur 2 is weergegeven hoe retinal is gebonden aan een restgroep van de peptideketen van opsine. Na de isomerisatie wordt retinal losgekoppeld van opsine. In figuur 2 is de eerste stap van het loskoppelen weergegeven. In deze eerste stap spelen twee watermoleculen een belangrijke rol.$$, 'inline'),
  ('f4d46b38-eeaf-462a-967d-c24ac36f4738', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$figuur 2 — loskoppelen van retinal van opsine (stap 1)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context6.png$$,
   $$figuur 2: schematische weergave van stap 1 van het loskoppelen van retinal (gebonden als een geprotoneerde C=N⁺-eenheid via C14-C15 aan de peptideketen (CH₂)₄) van opsine. Links van de pijl: de carboxylaatgroep van een Glu-restgroep (O=C-O⁻) is via twee, in een keten waterstofgebrugde watermoleculen verbonden met het geprotoneerde stikstofatoom van retinal. Rechts van de pijl (na stap 1): de carboxylgroep is geprotoneerd (O=C-OH), de twee watermoleculen zijn weer losse H₂O-moleculen, en het stikstofatoom van de retinal-eenheid is ongeladen geworden (C=N̄, met een formele lading).$$, 'inline'),
  ('3397b052-8515-459f-9eae-e3f70d2a704e', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$Glu-restgroep tegenover retinal; ladingen bepalen oriëntatie watermoleculen$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context7.png$$,
   $$In de holte van opsine is tegenover het gebonden retinal een restgroep van Glu aanwezig. Door de afstanden en aanwezige ladingen in de holte zijn de watermoleculen links van de pijl op een specifieke wijze georiënteerd ten opzichte van de restgroepen in opsine. Hierbij spelen waterstofbruggen en nog een andere soort binding een rol.$$, 'inline'),
  ('c8d541f0-e28b-4856-9d86-1acef0fa5722', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$watermoleculen blijven na stap 1 met waterstofbruggen gebonden$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context8.png$$,
   $$De na stap 1 weergegeven watermoleculen blijven aanwezig in de holte van opsine. Ze zijn hierbij onder andere met waterstofbruggen gebonden aan restgroepen van de peptideketen.$$, 'inline'),
  ('5e173c78-5c80-4b67-9cbe-550e19d17632', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$opsine bevindt zich deels in het celmembraan$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context9.png$$,
   $$Opsine bevindt zich deels in het celmembraan. In figuur 3 is vereenvoudigd weergegeven hoe opsine zich volgens onderzoekers in het celmembraan bevindt. Voor de duidelijkheid is een deel van het celmembraan lichter weergegeven.$$, 'inline'),
  ('6e3c961a-8d8c-4f1a-af24-3d34b9790f44', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$figuur 3 — opsine in het celmembraan (gebieden X en Y)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context10.png$$,
   $$figuur 3: vereenvoudigde weergave van opsine als een peptideketen die het celmembraan meerdere malen doorkruist (transmembraan-hydrofobe segmenten; een deel van het celmembraan is lichter weergegeven); de N-terminus (H₂N, aminozuur 1) bevindt zich aan de binnenkant van de cel, de C-terminus (aminozuur 350, met een COOH-groep) aan de buitenkant; twee gebieden van de keten zijn vetgedrukt aangeduid met de letters X en Y.$$, 'inline'),
  ('03388d61-6c73-46f3-b312-cfd3bbc42ea6', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$hydropathie-index geeft hydrofiel/hydrofoob karakter aan$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context11.png$$,
   $$De onderzoekers hebben de modelvoorstelling onder andere gebaseerd op de hydropathie-index. Deze index wordt modelmatig berekend en geeft aan in hoeverre een aminozuureenheid in een peptideketen hydrofiel of hydrofoob is. Hoe hoger de hydropathie-index, hoe meer de hydrofobe eigenschappen overheersen. In figuur 4 is de hydropathie-index van alle aminozuureenheden van opsine weergegeven.$$, 'inline'),
  ('9e268929-5455-46c9-8ff8-5b7c1a28e69d', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$figuur 4 — hydropathie-index van opsine (aminozuur 0-350)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context12.png$$,
   $$figuur 4: grafiek van de hydropathie-index (y-as, van −1,0 tot 2,0) tegen het nummer van de aminozuureenheid (x-as, van 0 tot 350) voor alle aminozuureenheden van opsine; de grafiek toont een golvend patroon met meerdere pieken boven 1,0 (rond aminozuur 50, 100-150, 220-230 en 280-290) en dalen tot onder 0 (rond aminozuur 0, 200 en 250-270), passend bij afwisselend hydrofobe (transmembraan) en hydrofiele segmenten.$$, 'inline'),
  ('9096c564-8a03-41a6-aa65-17501b0400ed', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$gebieden X en Y in figuur 3 schatten met behulp van figuur 4$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context13.png$$,
   $$In figuur 3 zijn twee gebieden uit opsine vetgedrukt en aangeduid met de letters X en Y. Deze gebieden bevatten een aantal aminozuureenheden. De nummers van deze aminozuureenheden kunnen met behulp van figuur 4 worden geschat.$$, 'inline'),
  ('027d38ff-ede9-4997-a13f-7e564984444b', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$drie varianten van opsine; DNA-codering vanaf base 826$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context14.png$$,
   $$In het menselijk oog komen drie verschillende varianten van opsine voor. De peptideketen van elke opsine heeft een iets andere ruimtelijke bouw. Hierdoor treedt de isomerisatie van retinal op bij verschillende kleuren licht, zoals rood en groen. De genen voor de ‘rode’ en ‘groene’ opsine zijn voor een groot deel aan elkaar gelijk. In figuur 5 is een gedeelte van het coderende DNA van beide varianten weergegeven vanaf de base met nummer 826. De genetische code van beide opsines begint hierbij bij base nummer 1. Het startcodon codeert voor de aminozuureenheid met nummer 1.$$, 'inline'),
  ('9cfeb76e-7ded-45bc-bb42-ea48f7049748', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$figuur 5 — DNA-basenvolgorde ‘rode’ en ‘groene’ opsine vanaf base 826$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context15.png$$,
   $$figuur 5: gedeelte van het coderende DNA vanaf base nummer 826 (met een pijl aangegeven): ‘rode’ opsine: GCGTACTGCGTCTGC…; ‘groene’ opsine: GCATTCTGCTTCTGC…$$, 'inline'),
  ('baa25513-0ed2-4033-b63e-19b6ba8028b8', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$eerste verschillende aminozuureenheid af te leiden uit figuur 5$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context16.png$$,
   $$Uit de basenvolgordes in figuur 5 valt het nummer af te leiden van de eerste aminozuureenheid die in ‘rode’ opsine anders is dan in ‘groene’ opsine.$$, 'inline'),
  ('202b61c2-cd3b-4e8d-9e0e-b71197c3cbb0', 'b9fb16b2-9bfd-4696-aecf-e3015b91ef93', $$uitwerkbijlage vraag 11 — watermoleculen en restgroepen na stap 1$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-retinal-in-het-oog-context17.png$$,
   $$Weergave (identiek aan het rechterdeel van figuur 2, na stap 1): de geprotoneerde carboxylgroep van Glu (O=C-OH), twee losse watermoleculen, en de gebonden retinal-eenheid (C₁₈H₂₆-CH-C=N̄, verbonden via (CH₂)₄ aan de peptideketen van opsine) — hierop moet een waterstofbrug tussen een watermolecuul en een van de weergegeven restgroepen worden getekend.$$, 'uitwerkbijlage'),
  ('bc0a3fd6-c86c-4827-8025-e00e4597fd9b', '30d00c2e-bdf8-4d98-9e5a-48941e555fb0', $$inleiding — biodieselproductie vormt ook glycerol$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-slim-gebruik-van-glycerol-context1.png$$,
   $$Biodiesel wordt geproduceerd door methanol toe te voegen aan plantaardige olie of dierlijk vet. Hierbij treedt een reactie op waarbij esters van methanol en vetzuren worden gevormd. Tevens wordt hierbij glycerol (propaan-1,2,3-triol) gevormd.$$, 'inline'),
  ('cb559178-bbdc-4292-8600-6c563e5a06f9', '30d00c2e-bdf8-4d98-9e5a-48941e555fb0', $$glycerol-overschot; reactie 1 — glycerol naar butaandizuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-slim-gebruik-van-glycerol-context2.png$$,
   $$Door de toename van de biodieselproductie is een overschot aan glycerol op de wereldmarkt ontstaan. Dit heeft geleid tot onderzoek naar de omzetting van glycerol met behulp van micro-organismen tot waardevolle chemicaliën. Een van deze chemicaliën is butaandizuur. De bacterie Anaerobiospirillum succiniciproducens kan onder zuurstofloze omstandigheden glycerol omzetten tot butaandizuur (C₄H₆O₄). De vergelijking van deze omzetting is hieronder weergegeven.
C₃H₈O₃ + CO₂ → C₄H₆O₄ + H₂O (reactie 1)$$, 'inline'),
  ('4662a3ad-7ec3-49ee-a711-7c28287fcba3', '30d00c2e-bdf8-4d98-9e5a-48941e555fb0', $$reactie 2 — glucose naar butaandizuur (4 mol uit 3 mol glucose)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-slim-gebruik-van-glycerol-context3.png$$,
   $$De bacterie kan ook glucose omzetten tot butaandizuur. In deze reactie (reactie 2) reageert glucose met koolstofdioxide tot butaandizuur, ethaanzuur en water. In reactie 2 ontstaat 4 mol butaandizuur uit 3 mol glucose.$$, 'inline'),
  ('47b6e065-8562-45ca-86be-a55512604c70', '30d00c2e-bdf8-4d98-9e5a-48941e555fb0', $$experiment — gelijktijdige omzetting van glycerol en glucose$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-slim-gebruik-van-glycerol-context4.png$$,
   $$Reactie 1 verloopt traag. Reactie 2 verloopt sneller, maar door de bacteriën worden dan meer bijproducten gevormd. Een groep onderzoekers heeft onderzocht of de productie van butaandizuur uit glycerol kan worden geoptimaliseerd door de bacteriën gelijktijdig glycerol en glucose te laten omzetten. Ze voerden een serie experimenten uit waarbij zij de bacteriën lieten groeien in een mengsel met enkel glycerol en in mengsels van glycerol met wisselende gehaltes glucose. Bij een mengsel met een startgehalte van 5,00 g L⁻¹ glycerol en 1,25 g L⁻¹ glucose werd uiteindelijk 7,3 g L⁻¹ butaandizuur geproduceerd.$$, 'inline'),
  ('7069d9e2-33d4-44d8-a472-38f011382e98', '30d00c2e-bdf8-4d98-9e5a-48941e555fb0', $$vormingswarmten en reactiewarmte; verdeling 85%/15% over reactie 1/2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-slim-gebruik-van-glycerol-context5.png$$,
   $$Reacties 1 en 2 zijn beide exotherm. De vrijgekomen energie wordt door de bacteriën gebruikt voor groei. De vormingswarmte van butaandizuur is −9,40·10⁵ J mol⁻¹ en die van glycerol is −6,64·10⁵ J mol⁻¹. De reactiewarmte van reactie 2 is −1,82·10⁵ J per mol butaandizuur. Bij de gebruikte omstandigheden wordt 85% van het butaandizuur gevormd uit reactie 1.$$, 'inline'),
  ('8e8fdc8d-f1fb-4f7d-8888-177f3f3fae72', '30d00c2e-bdf8-4d98-9e5a-48941e555fb0', $$pH-verlaging door butaandizuurvorming; natronloog houdt pH constant$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-slim-gebruik-van-glycerol-context6.png$$,
   $$De vorming van butaandizuur zorgt voor een verlaging van de pH van het reactiemengsel. Om de pH constant te houden, wordt gedurende het experiment natronloog aan het mengsel toegevoegd. Hierdoor vormt zich uiteindelijk een buffer in het reactiemengsel.$$, 'inline'),
  ('cb4b32fb-fc32-455d-aba7-380a5ef36649', '30d00c2e-bdf8-4d98-9e5a-48941e555fb0', $$NaOH-verbruik en dissociatiepercentages van butaandizuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-slim-gebruik-van-glycerol-context7.png$$,
   $$Bij het experiment met uitsluitend glycerol bleek dat de opbrengst aan butaandizuur maximaal was als het gehalte glycerol in de reactor constant werd gehouden. De hoeveelheid glycerol die tijdens het verloop van het experiment moet worden aangevuld, kon worden bepaald door te meten hoeveel NaOH er nodig was om de pH constant te houden. Bij de gebruikte pH was het door de bacteriën gevormde butaandizuur (C₄H₆O₄) voor 87% omgezet tot C₄H₄O₄²⁻ en voor 13% tot C₄H₅O₄⁻. In het experiment had in totaal 7,50 mL 2,00 M natronloog gereageerd.$$, 'inline'),
  ('1bc50ca4-bd1c-40aa-9bf0-9eb528e4a721', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$inleiding — ESET en EMB als geurbepalende stoffen in doerian$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context1.png$$,
   $$Doerian is een vrucht met een kenmerkende geur. De een houdt ervan terwijl de ander de geur weerzinwekkend vindt. Uit onderzoek is gebleken dat in doerians vooral twee verbindingen geurbepalend zijn: ESET en EMB. Als een van beide verbindingen ontbreekt, is de kenmerkende doerian-geur er niet. De structuurformules van deze verbindingen zijn weergegeven in figuur 1.$$, 'inline'),
  ('0632dd22-6318-4753-82b5-f89cad621fc3', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$figuur 1 — structuurformules van ESET en EMB$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context2.png$$,
   $$figuur 1: structuurformules van ESET (CH₃-CH(SH)-S-CH₂-CH₃) en EMB (CH₃-CH₂-CH(CH₃)-C(=O)-O-CH₂-CH₃).$$, 'inline'),
  ('5a97a85a-54a2-4177-bc3b-5bc60333793d', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$ESET komt voor als twee stereo-isomeren in doerians$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context3.png$$,
   $$Gebleken is dat van ESET twee stereo-isomeren voorkomen in doerians.$$, 'inline'),
  ('1cd17f45-ea85-453e-adf8-6f852f5e7e10', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$analoga met 2H/13C; ESET-13 gemaakt uit ethanal met twee 13C$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context4.png$$,
   $$Uit eerder onderzoek was de aanwezigheid van een groot aantal stoffen in doerians al bekend. Om de gehaltes van deze stoffen te kunnen bepalen, zijn van deze stoffen analoga gemaakt. Dit zijn stoffen waarbij in de moleculen een of meer atomen zijn vervangen door bijvoorbeeld ²H en ¹³C. In ESET werden twee ¹²C-atomen vervangen door ¹³C-atomen. De gevormde stof wordt in het vervolg aangeduid met ESET-13. ESET-13 werd gemaakt door gebruik te maken van ethanal, waarin twee ¹³C-atomen aanwezig zijn. In figuur 2 zijn de hierbij verlopende reacties weergegeven.$$, 'inline'),
  ('13b39c40-6715-429c-a17f-28ac7620578d', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$figuur 2 — synthese van ESET-13 uit ethanal (stap 1-4)$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context5.png$$,
   $$figuur 2: vier stappen van de synthese van ESET-13.
stap 1 (snel, evenwicht): CH₃-CH₂-SH + OH⁻ ⇌ CH₃-CH₂-S⁻ + H₂O
stap 2 (langzaam, evenwicht): CH₃-CH₂-S⁻ + ¹³CH₃-¹³C(=O)-H ⇌ X
stap 3 (snel, evenwicht): X + H₂O ⇌ ¹³CH₃-¹³C(OH)(H)-S-CH₂-CH₃ + OH⁻
stap 4 (snel): ¹³CH₃-¹³C(OH)(H)-S-CH₂-CH₃ + H₂S → ¹³CH₃-¹³C(SH)(H)-S-CH₂-CH₃ (ESET-13) + H₂O$$, 'inline'),
  ('0637082b-1e16-455c-a834-a20348e31cb5', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$stap 2 levert uitsluitend deeltje X; mechanisme op uitwerkbijlage$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context6.png$$,
   $$In stap 2 wordt uitsluitend deeltje X gevormd. Het mechanisme van de reactie in stap 2 is op de uitwerkbijlage onvolledig weergegeven.$$, 'inline'),
  ('2663aed4-f9d8-49db-81eb-7a6d0ab8dee1', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$stap 2 is de snelheidsbepalende stap$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context7.png$$,
   $$Van de weergegeven omzettingen in figuur 2 is stap 2 de snelheidsbepalende stap. Van stap 2 en 3 zijn drie mogelijke energiediagrammen weergegeven in figuur 3.$$, 'inline'),
  ('b6ffee08-bcdf-4e65-b648-ff5d40b9cf4f', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$figuur 3 — energiediagrammen P, Q en R voor stap 2 en stap 3$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context8.png$$,
   $$figuur 3: drie mogelijke energiediagrammen (P, Q, R) voor stap 2 en stap 3 uit figuur 2, elk met energie op de y-as tegen het reactieverloop (van beginstoffen stap 2 naar producten stap 3), met tussenproduct X als lokaal minimum tussen twee geactiveerde toestanden (met * aangegeven); de drie diagrammen verschillen in de relatieve hoogte van de twee energiebarrières (activeringsenergieën) van stap 2 en stap 3.$$, 'inline'),
  ('68de90a5-ef6b-4a71-a774-6b9e87d5bae8', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$geïsoleerde stof met kookpunt ESET; massaspectrum via [M-H]+ techniek$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context9.png$$,
   $$Na de reacties die zijn weergegeven in figuur 2, is uit het reactiemengsel een stof geïsoleerd met hetzelfde kookpunt als dat van ESET. Om te onderzoeken of deze stof inderdaad ESET-13 is, is van de stof een massaspectrum genomen. Bij de gebruikte techniek worden H⁺-ionen opgenomen, waarbij het molecuul-ion [M–H]⁺ wordt gevormd. Uit het molecuul-ion worden vervolgens fragmenten gevormd. In figuur 4 is het massaspectrum van ESET-13 weergegeven.$$, 'inline'),
  ('4e791103-ce5a-4b66-a069-2f01caa65da0', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$figuur 4 — massaspectrum van ESET-13$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context10.png$$,
   $$figuur 4: massaspectrum van ESET-13 (intensiteit in % op de y-as tegen m/z op de x-as, bereik 0-130). Pieken zijn zichtbaar bij ongeveer m/z = 63 (~65%), m/z = 91 (basispiek, 100%) en m/z = 126 (~15%), met enkele kleinere pieken ernaast.$$, 'inline'),
  ('19d18713-4d50-4866-9274-ab8cdab56753', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$piek bij m/z = 91 door afsplitsing van een neutraal deeltje$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context11.png$$,
   $$De piek bij m/z = 91 kan worden verklaard uit het afsplitsen van een neutraal deeltje van het molecuul-ion.$$, 'inline'),
  ('114a8a03-9e1e-4d99-ac76-e48a707c0cb7', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$piek bij m/z = 63 door verbreken van één atoombinding$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context12.png$$,
   $$In het massaspectrum van ESET-13 komt een piek voor bij m/z = 63. Deze piek wordt veroorzaakt door een fragment dat is ontstaan na het verbreken van één atoombinding in ESET-13.$$, 'inline'),
  ('4b7e4d0b-0b76-42d7-8671-c99c1f357c53', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$doerian-pulp geanalyseerd met GC-MS$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context13.png$$,
   $$Om van alle aanwezige stoffen het gehalte te kunnen bepalen, wordt doerian-pulp enkele malen geëxtraheerd. Na de extracties wordt het verkregen mengsel met behulp van GC-MS geanalyseerd. Dat houdt in dat het mengsel met behulp van gaschromatografie (GC) wordt gescheiden, waarna elke afzonderlijke stof in een massaspectrometer (MS) wordt geleid.$$, 'inline'),
  ('8a19a6b2-4ba4-4ea1-b848-f0d1802389b9', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$tabel — signaalsterkte interne standaard en EMB voor twee doerians$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context14.png$$,
   $$Van twee doerians is het gehalte EMB bepaald met behulp van gaschromatografie. Ook is met proefpersonen onderzocht welke doerian een sterkere geur had. Een sterkere geur wordt vooral bepaald door een hoger gehalte van EMB. Bij dit onderzoek is een interne standaard gebruikt. De signaalsterkte van de interne standaard is recht evenredig met het ingespoten volume. Wanneer in het onderzoek verschillende volumes zijn ingespoten, kunnen zo de resultaten toch met elkaar worden vergeleken. In de tabel zijn de meetgegevens van beide doerians weergegeven.
tabel (signaalsterkte interne standaard / signaalsterkte EMB): doerian 1: 520 / 7250. doerian 2: 320 / 5610.$$, 'inline'),
  ('fee17eff-f303-4b33-abec-1202c0086f25', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$interne standaard thiofeen; molverhouding EMB : thiofeen = 1,0 : 0,18$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context15.png$$,
   $$Als interne standaard is een oplossing van thiofeen bereid met een molariteit van 1,20·10⁻² mol L⁻¹. Vervolgens werd 10,0 µL van deze oplossing toegevoegd aan 10,0 mL pulp van een doerian. Bij deze doerian bleek de molverhouding EMB : thiofeen = 1,0 : 0,18. De molaire massa van EMB is 130 g mol⁻¹. Bij de gebruikte gaschromatograaf is de signaalsterkte recht evenredig aan de hoeveelheid stof.$$, 'inline'),
  ('360fa51e-ca9e-4f88-be33-0c773e781dbf', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$uitwerkbijlage vraag 20 — twee sjablonen voor stereo-isomeren van ESET$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context16.png$$,
   $$Twee onvolledige tekensjablonen om de twee stereo-isomeren van ESET te tekenen: links een centraal koolstofatoom met drie reeds getekende bindingen (één gewone lijn, één wigbinding, één gestippelde binding) waaraan nog groepen moeten worden toegevoegd; rechts (na ‘en’) een leeg centraal koolstofatoom waaromheen de volledige stereo-isomeer nog getekend moet worden.$$, 'uitwerkbijlage'),
  ('7648ffe2-ae9a-496d-b0dd-896a30b17f7c', 'd7245c72-3848-4cbb-a38a-6f8a59157865', $$uitwerkbijlage vraag 21 — beginstoffen van stap 2$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-doerian-een-delicatesse-context17.png$$,
   $$Weergave van de beginstoffen van stap 2 (identiek aan figuur 2): CH₃-CH₂-S⁻ + ¹³CH₃-¹³C(=O)-H, met een pijl (stap 2) naar de nog te tekenen kant — hierop moet het mechanisme (structuurformule van deeltje X, niet-bindende elektronenparen, elektronenverplaatsingspijlen en formele ladingen) compleet worden gemaakt.$$, 'uitwerkbijlage');
insert into practice_questions (id, exercise_id, question_number, topics, keywords, question_summary, question_image_url, question_text, context_block_ids) values
  ('8aa84e7f-85c9-4342-8b54-fb95bd79d087', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', 1,
   '[{"domain": "Reacties", "subdomain": "Chemische processen"}]'::jsonb,
   '["methaanzuur", "methylmethanoaat", "hydrolyse", "ester", "structuurformule opstellen"]'::jsonb,
   $$Reactievergelijking in structuurformules opstellen voor de hydrolyse van methylmethanoaat tot methaanzuur en methanol$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-vraag1.png$$, $$Geef de reactievergelijking van stap 3 in structuurformules.$$, array['a9f7fbaa-9912-478b-ac9c-63a26e668f9f']::uuid[]),
  ('f701b0f2-c4b3-4602-9437-a39de44f5bd5', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', 2,
   '[{"domain": "Reacties", "subdomain": "Chemische processen"}, {"domain": "Rekenen en analyse", "subdomain": "Grootheden en relaties"}]'::jsonb,
   '["atoomeconomie", "totaalvergelijking", "molverhouding", "methaanzuur", "rendement synthese"]'::jsonb,
   $$Totaalvergelijking opstellen en de atoomeconomie berekenen voor de industriële productie van methaanzuur$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-vraag2.png$$, $$Voer de volgende opdrachten uit:
− Geef de totaalvergelijking van het hele proces.
− Bereken de atoomeconomie van deze productie van methaanzuur.$$, array['a9f7fbaa-9912-478b-ac9c-63a26e668f9f', 'bec82752-c2ce-4ae4-b1e7-6e9a540b56b8']::uuid[]),
  ('33a92e59-3044-4848-a5cd-fea6f56b1750', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', 3,
   '[{"domain": "Rekenen en analyse", "subdomain": "Grootheden en relaties"}]'::jsonb,
   '["stoichiometrie", "dichtheid", "molaire massa", "volume berekenen", "waterstofproductie"]'::jsonb,
   $$Benodigd volume methaanzuur berekenen voor de productie van een gegeven hoeveelheid waterstofgas$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-vraag3.png$$, $$Bereken het volume in L methaanzuur dat minstens nodig is om 5,64 kg waterstof te kunnen produceren. Geef de uitkomst in het juiste aantal significante cijfers.$$, array['2dedf94c-cd97-4cec-a860-36a7bfe54270']::uuid[]),
  ('ff693ac5-5636-4cd1-b59e-7b2b38296fc9', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', 4,
   '[{"domain": "Reacties", "subdomain": "Chemische processen"}]'::jsonb,
   '["zuurrest-ion", "basisch milieu", "reactievergelijking", "methaanzuur", "zuur-base reactie"]'::jsonb,
   $$Reactievergelijking opstellen voor de vorming van het zuurrest-ion van methaanzuur in basisch milieu$$,
   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2021-ii-waterstofautos-die-methaanzuur-tanken-vraag4.png$$, $$Geef de reactievergelijking van deze omzetting.$$, array['d8826dda-e56f-49f7-af2d-ad60284b6b53']::uuid[]),
  ('c56d37cb-7834-475e-9525-1461c96a7b7c', '4c13293e-eac3-456b-a411-3f4b5a19ad7d', 5,
   '[{"domain": "Materie", "subdomain": "Deeltjesmodellen"}]'::jsonb,
   '["formele lading", "ionlading berekenen", "complex ion", "ladingsbalans", "iridium"]'::jsonb,
   $$Lading van een centraal metaalion afleiden uit de totale lading van een complex deeltje$$,
